mapper.insert:
/* 메뉴 접근 로그 등록	menu.insertMenuAccessLog */
INSERT	INTO	COM_MENU_ACCESS_LOG	(
	COMP_ID,	PGM_ID,	USER_ID,
	IP,			ACCESS_DT,	YEAR,	MON,
	DAY,		URL
)	VALUES	(
	IFNULL(#{compId}, 'NOT_LOGIN'),	#{pgmId},	#{userId},
	#{ip},		NOW(),	DATE_FORMAT(NOW(), '%Y'),	DATE_FORMAT(NOW(), '%m'),
	DATE_FORMAT(NOW(), '%d'),	#{url}
)

mapper.select:
/*	도움말 조회	menu.selectGuideCommentList	*/
SELECT	A.PGM_ID,	A.GUIDE_COMMENT
FROM	${templateDbId}.COM_PGM A
WHERE	A.COMP_ID = #{compId}
	AND	A.DELETE_DT IS NULL
	AND	(A.GUIDE_COMMENT IS NOT NULL AND A.GUIDE_COMMENT != '')
